    C_S_AXI_DATA_WIDTH = 32
)(
    input  wire                          ACLK,
    input  wire                          ARESET,
    input  wire                          ACLK_EN,
    input  wire [C_S_AXI_ADDR_WIDTH-1:0] AWADDR,
    input  wire                          AWVALID,
    output wire                          AWREADY,
    input  wire [C_S_AXI_DATA_WIDTH-1:0] WDATA,
    input  wire [C_S_AXI_DATA_WIDTH/8-1:0] WSTRB,
    input  wire                          WVALID,
    output wire                          WREADY,
    output wire [1:0]                    BRESP,
    output wire                          BVALID,
    input  wire                          BREADY,
    input  wire [C_S_AXI_ADDR_WIDTH-1:0] ARADDR,
    input  wire                          ARVALID,
    output wire                          ARREADY,
    output wire [C_S_AXI_DATA_WIDTH-1:0] RDATA,
    output wire [1:0]                    RRESP,
    output wire                          RVALID,
    input  wire                          RREADY,
    output wire                          interrupt,
    output wire [63:0]                   a_offset,
    output wire [63:0]                   b_offset,
    output wire [63:0]                   c_offset,
    output wire [63:0]                   n,
    output wire                          ap_start,
    input  wire                          ap_done,
    input  wire                          ap_ready,
    input  wire                          ap_idle
);
//------------------------Address Info-------------------
// Protocol Used: ap_ctrl_hs
//
// 0x00 : Control signals
//        bit 0  - ap_start (Read/Write/SC)
//        bit 1  - ap_done (Read/COR)
//        bit 2  - ap_idle (Read)
//        bit 3  - ap_ready (Read/COR)
//        bit 7  - auto_restart (Read/Write)
//        bit 9  - interrupt (Read)
//        others - reserved
// 0x04 : Global Interrupt Enable Register
//        bit 0  - Global Interrupt Enable (Read/Write)
//        others - reserved
// 0x08 : IP Interrupt Enable Register (Read/Write)
//        bit 0 - enable ap_done interrupt (Read/Write)
//        others - reserved
// 0x0c : IP Interrupt Status Register (Read/TOW)
//        bit 0 - ap_done (Read/TOW)
//        others - reserved
// 0x10 : Data signal of a_offset
//        bit 31~0 - a_offset[31:0] (Read/Write)
// 0x14 : Data signal of a_offset
//        bit 31~0 - a_offset[63:32] (Read/Write)
// 0x18 : reserved
// 0x1c : Data signal of b_offset
//        bit 31~0 - b_offset[31:0] (Read/Write)
// 0x20 : Data signal of b_offset
//        bit 31~0 - b_offset[63:32] (Read/Write)
// 0x24 : reserved
// 0x28 : Data signal of c_offset
//        bit 31~0 - c_offset[31:0] (Read/Write)
// 0x2c : Data signal of c_offset
//        bit 31~0 - c_offset[63:32] (Read/Write)
// 0x30 : reserved
// 0x34 : Data signal of n
//        bit 31~0 - n[31:0] (Read/Write)
// 0x38 : Data signal of n
//        bit 31~0 - n[63:32] (Read/Write)
// 0x3c : reserved
// (SC = Self Clear, COR = Clear on Read, TOW = Toggle on Write, COH = Clear on Handshake)

//------------------------Parameter----------------------
localparam
    ADDR_AP_CTRL         = 6'h00,
    ADDR_GIE             = 6'h04,
    ADDR_IER             = 6'h08,
    ADDR_ISR             = 6'h0c,
    ADDR_A_OFFSET_DATA_0 = 6'h10,
    ADDR_A_OFFSET_DATA_1 = 6'h14,
    ADDR_A_OFFSET_CTRL   = 6'h18,
    ADDR_B_OFFSET_DATA_0 = 6'h1c,
    ADDR_B_OFFSET_DATA_1 = 6'h20,
    ADDR_B_OFFSET_CTRL   = 6'h24,
    ADDR_C_OFFSET_DATA_0 = 6'h28,
    ADDR_C_OFFSET_DATA_1 = 6'h2c,
    ADDR_C_OFFSET_CTRL   = 6'h30,
    ADDR_N_DATA_0        = 6'h34,
    ADDR_N_DATA_1        = 6'h38,
    ADDR_N_CTRL          = 6'h3c,
    WRIDLE               = 2'd0,
    WRDATA               = 2'd1,
    WRRESP               = 2'd2,
    WRRESET              = 2'd3,
    RDIDLE               = 2'd0,
    RDDATA               = 2'd1,
    RDRESET              = 2'd2,
    ADDR_BITS                = 6;

//------------------------Local signal-------------------
    reg  [1:0]                    wstate = WRRESET;
    reg  [1:0]                    wnext;
    reg  [ADDR_BITS-1:0]          waddr;
    wire [C_S_AXI_DATA_WIDTH-1:0] wmask;
    wire                          aw_hs;
    wire                          w_hs;
    reg  [1:0]                    rstate = RDRESET;
    reg  [1:0]                    rnext;
    reg  [C_S_AXI_DATA_WIDTH-1:0] rdata;
    wire                          ar_hs;
    wire [ADDR_BITS-1:0]          raddr;
    // internal registers
    reg                           int_ap_idle = 1'b0;
    reg                           int_ap_ready = 1'b0;
    wire                          task_ap_ready;
    reg                           int_ap_done = 1'b0;
    wire                          task_ap_done;
    reg                           int_task_ap_done = 1'b0;
    reg                           int_ap_start = 1'b0;
    reg                           int_interrupt = 1'b0;
    reg                           int_auto_restart = 1'b0;
    reg                           auto_restart_status = 1'b0;
    wire                          auto_restart_done;
    reg                           int_gie = 1'b0;
    reg                           int_ier = 1'b0;
    reg                           int_isr = 1'b0;
    reg  [63:0]                   int_a_offset = 'b0;
    reg  [63:0]                   int_b_offset = 'b0;
    reg  [63:0]                   int_c_offset = 'b0;
    reg  [63:0]                   int_n = 'b0;

//------------------------Instantiation------------------


//------------------------AXI write fsm------------------
assign AWREADY = (wstate == WRIDLE);
assign WREADY  = (wstate == WRDATA);
assign BRESP   = 2'b00;  // OKAY
assign BVALID  = (wstate == WRRESP);
assign wmask   = { {8{WSTRB[3]}}, {8{WSTRB[2]}}, {8{WSTRB[1]}}, {8{WSTRB[0]}} };
assign aw_hs   = AWVALID & AWREADY;
assign w_hs    = WVALID & WREADY;

// wstate
always @(posedge ACLK) begin
    if (ARESET)
        wstate <= WRRESET;
    else if (ACLK_EN)
        wstate <= wnext;
end

// wnext
always @(*) begin
    case (wstate)
        WRIDLE:
            if (AWVALID)
                wnext = WRDATA;
            else
                wnext = WRIDLE;
        WRDATA:
            if (WVALID)
                wnext = WRRESP;
            else
                wnext = WRDATA;
        WRRESP:
            if (BREADY)
                wnext = WRIDLE;
            else
                wnext = WRRESP;
        default:
            wnext = WRIDLE;
    endcase
end

// waddr
always @(posedge ACLK) begin
    if (ACLK_EN) begin
        if (aw_hs)
            waddr <= {AWADDR[ADDR_BITS-1:2], {2{1'b0}}};
    end
end

//------------------------AXI read fsm-------------------
assign ARREADY = (rstate == RDIDLE);
assign RDATA   = rdata;
assign RRESP   = 2'b00;  // OKAY
assign RVALID  = (rstate == RDDATA);
assign ar_hs   = ARVALID & ARREADY;
assign raddr   = ARADDR[ADDR_BITS-1:0];

// rstate
always @(posedge ACLK) begin
    if (ARESET)
        rstate <= RDRESET;
    else if (ACLK_EN)
        rstate <= rnext;
end

// rnext
always @(*) begin
    case (rstate)
        RDIDLE:
            if (ARVALID)
                rnext = RDDATA;
            else
                rnext = RDIDLE;
        RDDATA:
            if (RREADY & RVALID)
                rnext = RDIDLE;
            else
                rnext = RDDATA;
        default:
            rnext = RDIDLE;
    endcase
end

// rdata
always @(posedge ACLK) begin
    if (ACLK_EN) begin
        if (ar_hs) begin
            rdata <= 'b0;
            case (raddr)
                ADDR_AP_CTRL: begin
                    rdata[0] <= int_ap_start;
                    rdata[1] <= int_task_ap_done;
                    rdata[2] <= int_ap_idle;
                    rdata[3] <= int_ap_ready;
                    rdata[7] <= int_auto_restart;
                    rdata[9] <= int_interrupt;
                end
                ADDR_GIE: begin
                    rdata <= int_gie;
                end
                ADDR_IER: begin
                    rdata <= int_ier;
                end
                ADDR_ISR: begin
                    rdata <= int_isr;
                end
                ADDR_A_OFFSET_DATA_0: begin
                    rdata <= int_a_offset[31:0];
                end
                ADDR_A_OFFSET_DATA_1: begin
                    rdata <= int_a_offset[63:32];
                end
                ADDR_B_OFFSET_DATA_0: begin
                    rdata <= int_b_offset[31:0];
                end
                ADDR_B_OFFSET_DATA_1: begin
                    rdata <= int_b_offset[63:32];
                end
                ADDR_C_OFFSET_DATA_0: begin
                    rdata <= int_c_offset[31:0];
                end
                ADDR_C_OFFSET_DATA_1: begin
                    rdata <= int_c_offset[63:32];
                end
                ADDR_N_DATA_0: begin
                    rdata <= int_n[31:0];
                end
                ADDR_N_DATA_1: begin
                    rdata <= int_n[63:32];
                end
            endcase
        end
    end
end


//------------------------Register logic-----------------
assign interrupt         = int_interrupt;
assign ap_start          = int_ap_start;
assign task_ap_done      = (ap_done && !auto_restart_status) || auto_restart_done;
assign task_ap_ready     = ap_ready && !int_auto_restart;
assign auto_restart_done = auto_restart_status && (ap_idle && !int_ap_idle);
assign a_offset          = int_a_offset;
assign b_offset          = int_b_offset;
assign c_offset          = int_c_offset;
assign n                 = int_n;
// int_interrupt
always @(posedge ACLK) begin
    if (ARESET)
        int_interrupt <= 1'b0;
    else if (ACLK_EN) begin
        if (int_gie && (|int_isr))
            int_interrupt <= 1'b1;
        else
            int_interrupt <= 1'b0;
    end
end

// int_ap_start
always @(posedge ACLK) begin
    if (ARESET)
        int_ap_start <= 1'b0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_AP_CTRL && WSTRB[0] && WDATA[0])
            int_ap_start <= 1'b1;
        else if (ap_done & int_auto_restart)
            int_ap_start <= 1'b1; // auto restart
        else
            int_ap_start <= 1'b0; // self clear
    end
end

// int_ap_done
always @(posedge ACLK) begin
    if (ARESET)
        int_ap_done <= 1'b0;
    else if (ACLK_EN) begin
            int_ap_done <= ap_done;
    end
end

// int_task_ap_done
always @(posedge ACLK) begin
    if (ARESET)
        int_task_ap_done <= 1'b0;
    else if (ACLK_EN) begin
        if (task_ap_done)
            int_task_ap_done <= 1'b1;
        else if (ar_hs && raddr == ADDR_AP_CTRL)
            int_task_ap_done <= 1'b0; // clear on read
    end
end

// int_ap_idle
always @(posedge ACLK) begin
    if (ARESET)
        int_ap_idle <= 1'b0;
    else if (ACLK_EN) begin
            int_ap_idle <= ap_idle;
    end
end

// int_ap_ready
always @(posedge ACLK) begin
    if (ARESET)
        int_ap_ready <= 1'b0;
    else if (ACLK_EN) begin
        if (task_ap_ready)
            int_ap_ready <= 1'b1;
        else if (ar_hs && raddr == ADDR_AP_CTRL)
            int_ap_ready <= 1'b0;
    end
end

// int_auto_restart
always @(posedge ACLK) begin
    if (ARESET)
        int_auto_restart <= 1'b0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_AP_CTRL && WSTRB[0])
            int_auto_restart <= WDATA[7];
    end
end

// auto_restart_status
always @(posedge ACLK) begin
    if (ARESET)
        auto_restart_status <= 1'b0;
    else if (ACLK_EN) begin
        if (int_auto_restart)
            auto_restart_status <= 1'b1;
        else if (ap_idle)
            auto_restart_status <= 1'b0;
    end
end

// int_gie
always @(posedge ACLK) begin
    if (ARESET)
        int_gie <= 1'b0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_GIE && WSTRB[0])
            int_gie <= WDATA[0];
    end
end

// int_ier
always @(posedge ACLK) begin
    if (ARESET)
        int_ier <= 1'b0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_IER && WSTRB[0])
            int_ier <= WDATA[0];
    end
end

// int_isr
always @(posedge ACLK) begin
    if (ARESET)
        int_isr <= 1'b0;
    else if (ACLK_EN) begin
        if (int_ier & ap_done)
            int_isr <= 1'b1;
        else if (w_hs && waddr == ADDR_ISR && WSTRB[0])
            int_isr <= int_isr ^ WDATA[0]; // toggle on write
    end
end

// int_a_offset[31:0]
always @(posedge ACLK) begin
    if (ARESET)
        int_a_offset[31:0] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_A_OFFSET_DATA_0)
            int_a_offset[31:0] <= (WDATA[31:0] & wmask) | (int_a_offset[31:0] & ~wmask);
    end
end

// int_a_offset[63:32]
always @(posedge ACLK) begin
    if (ARESET)
        int_a_offset[63:32] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_A_OFFSET_DATA_1)
            int_a_offset[63:32] <= (WDATA[31:0] & wmask) | (int_a_offset[63:32] & ~wmask);
    end
end

// int_b_offset[31:0]
always @(posedge ACLK) begin
    if (ARESET)
        int_b_offset[31:0] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_B_OFFSET_DATA_0)
            int_b_offset[31:0] <= (WDATA[31:0] & wmask) | (int_b_offset[31:0] & ~wmask);
    end
end

// int_b_offset[63:32]
always @(posedge ACLK) begin
    if (ARESET)
        int_b_offset[63:32] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_B_OFFSET_DATA_1)
            int_b_offset[63:32] <= (WDATA[31:0] & wmask) | (int_b_offset[63:32] & ~wmask);
    end
end

// int_c_offset[31:0]
always @(posedge ACLK) begin
    if (ARESET)
        int_c_offset[31:0] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_C_OFFSET_DATA_0)
            int_c_offset[31:0] <= (WDATA[31:0] & wmask) | (int_c_offset[31:0] & ~wmask);
    end
end

// int_c_offset[63:32]
always @(posedge ACLK) begin
    if (ARESET)
        int_c_offset[63:32] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_C_OFFSET_DATA_1)
            int_c_offset[63:32] <= (WDATA[31:0] & wmask) | (int_c_offset[63:32] & ~wmask);
    end
end

// int_n[31:0]
always @(posedge ACLK) begin
    if (ARESET)
        int_n[31:0] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_N_DATA_0)
            int_n[31:0] <= (WDATA[31:0] & wmask) | (int_n[31:0] & ~wmask);
    end
end

// int_n[63:32]
always @(posedge ACLK) begin
    if (ARESET)
        int_n[63:32] <= 0;
    else if (ACLK_EN) begin
        if (w_hs && waddr == ADDR_N_DATA_1)
            int_n[63:32] <= (WDATA[31:0] & wmask) | (int_n[63:32] & ~wmask);
    end
end

//synthesis translate_off
always @(posedge ACLK) begin
    if (ACLK_EN) begin
        if (int_gie & ~int_isr & int_ier & ap_done)
            $display ("// Interrupt Monitor : interrupt for ap_done detected @ \"%0t\"", $time);
    end
end
//synthesis translate_on

//------------------------Memory logic-------------------

endmodule

module VecAdd_fsm (
  input wire ap_clk,
  input wire ap_rst_n,
  input wire ap_start,
  output wire ap_done,
  output wire ap_ready,
  output wire ap_idle,
  output wire Add_0__ap_start,
  input wire Add_0__ap_ready,
  input wire Add_0__ap_done,
  input wire Add_0__ap_idle,
  output wire Add_0__is_done,
  input wire Add_0__n_in,
  output wire Add_0__n,
  output wire Mmap2Stream_0__ap_start,
  input wire Mmap2Stream_0__ap_ready,
  input wire Mmap2Stream_0__ap_done,
  input wire Mmap2Stream_0__ap_idle,
  output wire Mmap2Stream_0__is_done,
  input wire [63:0] Mmap2Stream_0__mmap_offset_in,
  output wire [63:0] Mmap2Stream_0__mmap_offset,
  input wire Mmap2Stream_0__n_in,
  output wire Mmap2Stream_0__n,
  output wire Mmap2Stream_1__ap_start,
  input wire Mmap2Stream_1__ap_ready,
  input wire Mmap2Stream_1__ap_done,
  input wire Mmap2Stream_1__ap_idle,
  output wire Mmap2Stream_1__is_done,
  input wire [63:0] Mmap2Stream_1__mmap_offset_in,
  output wire [63:0] Mmap2Stream_1__mmap_offset,
  input wire Mmap2Stream_1__n_in,
  output wire Mmap2Stream_1__n,
  output wire Stream2Mmap_0__ap_start,
  input wire Stream2Mmap_0__ap_ready,
  input wire Stream2Mmap_0__ap_done,
  input wire Stream2Mmap_0__ap_idle,
  output wire Stream2Mmap_0__is_done,
  input wire [63:0] Stream2Mmap_0__mmap_offset_in,
  output wire [63:0] Stream2Mmap_0__mmap_offset,
  input wire Stream2Mmap_0__n_in,
  output wire Stream2Mmap_0__n
);

reg [1:0] Add_0__state;
wire Add_0__ap_start;
wire Add_0__ap_done;
wire Add_0__is_done;
wire Add_0__ap_idle;
wire Add_0__ap_ready;
reg Add_0__n_reg;
reg [1:0] Mmap2Stream_0__state;
wire Mmap2Stream_0__ap_start;
wire Mmap2Stream_0__ap_done;
wire Mmap2Stream_0__is_done;
wire Mmap2Stream_0__ap_idle;
wire Mmap2Stream_0__ap_ready;
reg [63:0] Mmap2Stream_0__mmap_offset_reg;
reg Mmap2Stream_0__n_reg;
reg [1:0] Mmap2Stream_1__state;
wire Mmap2Stream_1__ap_start;
wire Mmap2Stream_1__ap_done;
wire Mmap2Stream_1__is_done;
wire Mmap2Stream_1__ap_idle;
wire Mmap2Stream_1__ap_ready;
reg [63:0] Mmap2Stream_1__mmap_offset_reg;
reg Mmap2Stream_1__n_reg;
reg [1:0] Stream2Mmap_0__state;
wire Stream2Mmap_0__ap_start;
wire Stream2Mmap_0__ap_done;
wire Stream2Mmap_0__is_done;
wire Stream2Mmap_0__ap_idle;
wire Stream2Mmap_0__ap_ready;
reg [63:0] Stream2Mmap_0__mmap_offset_reg;
reg Stream2Mmap_0__n_reg;
reg [1:0] __tapa_state;
wire ap_rst;
wire __tapa_start_q;
wire __tapa_done_q;

assign Add_0__ap_start = (Add_0__state == 2'b01);
assign Add_0__is_done = (Add_0__state == 2'b10);
assign Add_0__n = Add_0__n_reg;
assign Mmap2Stream_0__ap_start = (Mmap2Stream_0__state == 2'b01);
assign Mmap2Stream_0__is_done = (Mmap2Stream_0__state == 2'b10);
assign Mmap2Stream_0__mmap_offset = Mmap2Stream_0__mmap_offset_reg;
assign Mmap2Stream_0__n = Mmap2Stream_0__n_reg;
assign Mmap2Stream_1__ap_start = (Mmap2Stream_1__state == 2'b01);
assign Mmap2Stream_1__is_done = (Mmap2Stream_1__state == 2'b10);
assign Mmap2Stream_1__mmap_offset = Mmap2Stream_1__mmap_offset_reg;
assign Mmap2Stream_1__n = Mmap2Stream_1__n_reg;
assign Stream2Mmap_0__ap_start = (Stream2Mmap_0__state == 2'b01);
assign Stream2Mmap_0__is_done = (Stream2Mmap_0__state == 2'b10);
assign Stream2Mmap_0__mmap_offset = Stream2Mmap_0__mmap_offset_reg;
assign Stream2Mmap_0__n = Stream2Mmap_0__n_reg;
assign ap_rst = !ap_rst_n;
assign __tapa_start_q = ap_start;
assign ap_idle = (__tapa_state == 2'b00);
assign __tapa_done_q = (__tapa_state == 2'b10);
assign ap_done = __tapa_done_q;
assign ap_ready = __tapa_done_q;
always @(posedge ap_clk) begin
  if (ap_rst) begin
    Add_0__state <= 2'b00;
  end else begin
    case (Add_0__state)
      2'b00: begin
        if (__tapa_start_q) begin
          Add_0__state <= 2'b01;
        end
      end
      2'b01: begin
        if ((Add_0__ap_ready && Add_0__ap_done)) begin
          Add_0__state <= 2'b10;
        end else begin
          if (Add_0__ap_ready) begin
            Add_0__state <= 2'b11;
          end
        end
      end
      2'b11: begin
        if (Add_0__ap_done) begin
          Add_0__state <= 2'b10;
        end
      end
      2'b10: begin
        if (__tapa_done_q) begin
          Add_0__state <= 2'b00;
        end
      end
      default: begin
        Add_0__state <= 2'b00;
      end
    endcase
  end
end

always @(posedge ap_clk) begin
  Add_0__n_reg <= Add_0__n_in;
end

always @(posedge ap_clk) begin
  if (ap_rst) begin
    Mmap2Stream_0__state <= 2'b00;
  end else begin
    case (Mmap2Stream_0__state)
      2'b00: begin
        if (__tapa_start_q) begin
          Mmap2Stream_0__state <= 2'b01;
        end
      end
      2'b01: begin
        if ((Mmap2Stream_0__ap_ready && Mmap2Stream_0__ap_done)) begin
          Mmap2Stream_0__state <= 2'b10;
        end else begin
          if (Mmap2Stream_0__ap_ready) begin
            Mmap2Stream_0__state <= 2'b11;
          end
        end
      end
      2'b11: begin
        if (Mmap2Stream_0__ap_done) begin
          Mmap2Stream_0__state <= 2'b10;
        end
      end
      2'b10: begin
        if (__tapa_done_q) begin
          Mmap2Stream_0__state <= 2'b00;
        end
      end
      default: begin
        Mmap2Stream_0__state <= 2'b00;
      end
    endcase
  end
end

always @(posedge ap_clk) begin
  Mmap2Stream_0__mmap_offset_reg <= Mmap2Stream_0__mmap_offset_in;
end

always @(posedge ap_clk) begin
  Mmap2Stream_0__n_reg <= Mmap2Stream_0__n_in;
end

always @(posedge ap_clk) begin
  if (ap_rst) begin
    Mmap2Stream_1__state <= 2'b00;
  end else begin
    case (Mmap2Stream_1__state)
      2'b00: begin
        if (__tapa_start_q) begin
